<?php
namespace App\Modules\Hr\Advance\Actions;
use App\Modules\Hr\Advance\Enums\AdvanceStatus; use App\Modules\Hr\Advance\Models\HrAdvance; use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext;
class CancelAdvanceAction { public function __construct(private HrAuditService $audit){} public function execute(HrAdvance $advance):HrAdvance{abort_unless($advance->legal_entity_id===app(TenantContext::class)->getId(),404);$owner=$advance->employee()->where('user_id',auth()->id())->exists();abort_unless($owner||auth()->user()?->hasHrPermission('hr.advances.approve'),403);abort_unless(in_array($advance->status,[AdvanceStatus::PendingManager,AdvanceStatus::PendingHr],true),422);$from=$advance->status;$advance->update(['status'=>AdvanceStatus::Cancelled,'decided_by'=>auth()->id(),'decided_at'=>now()]);$this->audit->log('advance_cancelled',$advance,['status'=>$from->value],['status'=>AdvanceStatus::Cancelled->value]);return $advance->fresh();} }
